diff --git a/Dapper/DynamicParameters.cs b/Dapper/DynamicParameters.cs
index f6708b5..80522fc 100644
--- a/Dapper/DynamicParameters.cs
+++ b/Dapper/DynamicParameters.cs
@@ -322,11 +322,24 @@ public T Get<T>(string name)
             {
                 if (default(T) is not null)
                 {
-                    throw new ApplicationException("Attempting to cast a DBNull to a non nullable type! Note that out/return parameters will not have updated values until the data stream completes (after the 'foreach' for Query(..., buffered: false), or after the GridReader has been disposed for QueryMultiple)");
+                    throw new InvalidCastException("Attempting to cast a DBNull to a non nullable type! Note that out/return parameters will not have updated values until the data stream completes (after the 'foreach' for Query(..., buffered: false), or after the GridReader has been disposed for QueryMultiple)");
                 }
                 return default!;
             }
-            return (T)val!;
+            if (val is T tVal) return tVal;
+            var type = Nullable.GetUnderlyingType(typeof(T)) ?? typeof(T);
+            if (val is IConvertible && typeof(IConvertible).IsAssignableFrom(type))
+            {
+                return (T)Convert.ChangeType(val, type, System.Globalization.CultureInfo.InvariantCulture);
+            }
+            try
+            {
+                return (T)val!;
+            }
+            catch (InvalidCastException)
+            {
+                throw new InvalidCastException($"Cannot convert value of type {val?.GetType().FullName ?? "null"} to {typeof(T).FullName}");
+            }
